CREATE TABLE `cli_vital_signs` (
  `ID` int NOT NULL AUTO_INCREMENT,
  `CODE` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Vital signs code',
  `PATIENT_ID` int NOT NULL COMMENT 'Reference to pat_patients',
  `VISIT_ID` int DEFAULT NULL COMMENT 'Reference to cli_visits',
  `EMR_HEADER_ID` int DEFAULT NULL COMMENT 'Reference to cli_emr_headers',
  `MEASUREMENT_DATE` datetime NOT NULL COMMENT 'Measurement date and time',
  `TEMPERATURE` decimal(5,2) DEFAULT NULL COMMENT 'Temperature in Celsius',
  `TEMPERATURE_METHOD` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Method: ORAL, AXILLARY, RECTAL, TYMPANIC',
  `HEART_RATE` int DEFAULT NULL COMMENT 'Heart rate (BPM)',
  `HEART_RHYTHM` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Heart rhythm: REGULAR, IRREGULAR',
  `BLOOD_PRESSURE_SYSTOLIC` int DEFAULT NULL COMMENT 'Systolic BP (mmHg)',
  `BLOOD_PRESSURE_DIASTOLIC` int DEFAULT NULL COMMENT 'Diastolic BP (mmHg)',
  `BLOOD_PRESSURE_METHOD` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Method: MANUAL, AUTOMATIC',
  `BLOOD_PRESSURE_POSITION` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Position: SITTING, STANDING, LYING',
  `RESPIRATORY_RATE` int DEFAULT NULL COMMENT 'Respiratory rate (breaths/min)',
  `OXYGEN_SATURATION` decimal(5,2) DEFAULT NULL COMMENT 'Oxygen saturation (%)',
  `OXYGEN_SATURATION_METHOD` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Method: PULSE_OXIMETER, ARTERIAL_BLOOD_GAS',
  `PAIN_SCALE` int DEFAULT NULL COMMENT 'Pain scale (0-10)',
  `PAIN_LOCATION` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Pain location',
  `PAIN_CHARACTERISTICS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Pain characteristics',
  `WEIGHT` decimal(6,2) DEFAULT NULL COMMENT 'Weight in kg',
  `HEIGHT` decimal(5,2) DEFAULT NULL COMMENT 'Height in cm',
  `BMI` decimal(5,2) DEFAULT NULL COMMENT 'Body Mass Index',
  `WAIST_CIRCUMFERENCE` decimal(5,2) DEFAULT NULL COMMENT 'Waist circumference (cm)',
  `HEAD_CIRCUMFERENCE` decimal(5,2) DEFAULT NULL COMMENT 'Head circumference (cm) - for pediatrics',
  `GLUCOSE_LEVEL` decimal(6,2) DEFAULT NULL COMMENT 'Blood glucose level (mg/dL)',
  `GLUCOSE_METHOD` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Method: FINGERSTICK, LAB',
  `GLUCOSE_TIMING` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Timing: FASTING, RANDOM, POSTPRANDIAL',
  `PULSE_OXIMETRY` int DEFAULT NULL COMMENT 'Pulse oximetry reading',
  `MEAN_ARTERIAL_PRESSURE` int DEFAULT NULL COMMENT 'Mean arterial pressure',
  `CENTRAL_VENOUS_PRESSURE` int DEFAULT NULL COMMENT 'CVP (mmHg)',
  `PULMONARY_ARTERY_PRESSURE_SYSTOLIC` int DEFAULT NULL COMMENT 'PA systolic (mmHg)',
  `PULMONARY_ARTERY_PRESSURE_DIASTOLIC` int DEFAULT NULL COMMENT 'PA diastolic (mmHg)',
  `PULMONARY_CAPILLARY_WEDGE_PRESSURE` int DEFAULT NULL COMMENT 'PCWP (mmHg)',
  `CARDIAC_OUTPUT` decimal(5,2) DEFAULT NULL COMMENT 'Cardiac output (L/min)',
  `CARDIAC_INDEX` decimal(5,2) DEFAULT NULL COMMENT 'Cardiac index (L/min/m?)',
  `SYSTEMIC_VASCULAR_RESISTANCE` int DEFAULT NULL COMMENT 'SVR (dynes/sec/cm?)',
  `INTRACRANIAL_PRESSURE` int DEFAULT NULL COMMENT 'ICP (mmHg)',
  `INTRAOCULAR_PRESSURE_RIGHT` int DEFAULT NULL COMMENT 'IOP right eye (mmHg)',
  `INTRAOCULAR_PRESSURE_LEFT` int DEFAULT NULL COMMENT 'IOP left eye (mmHg)',
  `MEASURED_BY` int DEFAULT NULL COMMENT 'Measured by staff ID',
  `MEASUREMENT_DEVICE` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Device used',
  `MEASUREMENT_LOCATION` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Location of measurement',
  `ABNORMAL_FLAGS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Abnormal flags (JSON)',
  `NOTES` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Measurement notes',
  `CREATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `LAST_UPDATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `STATUS` int NOT NULL DEFAULT '1',
  `CREATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_PROGRAM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`ID`),
  UNIQUE KEY `UK_CODE` (`CODE`),
  KEY `IDX_PATIENT_ID` (`PATIENT_ID`),
  KEY `IDX_VISIT_ID` (`VISIT_ID`),
  KEY `IDX_EMR_HEADER_ID` (`EMR_HEADER_ID`),
  KEY `IDX_MEASUREMENT_DATE` (`MEASUREMENT_DATE`),
  KEY `IDX_MEASURED_BY` (`MEASURED_BY`),
  KEY `IDX_STATUS` (`STATUS`),
  KEY `IDX_CREATED_AT` (`CREATED_AT`),
  KEY `IDX_CLI_VITAL_SIGNS_PATIENT_ID` (`PATIENT_ID`),
  KEY `IDX_CLI_VITAL_SIGNS_MEASUREMENT_DATE` (`MEASUREMENT_DATE`),
  CONSTRAINT `FK_VITAL_SIGNS_EMR_HEADER` FOREIGN KEY (`EMR_HEADER_ID`) REFERENCES `cli_emr_headers` (`ID`),
  CONSTRAINT `FK_VITAL_SIGNS_MEASURED_BY` FOREIGN KEY (`MEASURED_BY`) REFERENCES `sta_staff` (`ID`),
  CONSTRAINT `FK_VITAL_SIGNS_PATIENT` FOREIGN KEY (`PATIENT_ID`) REFERENCES `pat_patients` (`ID`),
  CONSTRAINT `FK_VITAL_SIGNS_VISIT` FOREIGN KEY (`VISIT_ID`) REFERENCES `cli_visits` (`ID`)
) ENGINE=InnoDB AUTO_INCREMENT=116 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Vital Signs Measurements';
